352→    fn shrink_array_single_element() {
353→        let typ = TypeInfo::Array {
354→            element: Box::new(TypeInfo::Int),
355→        };
356→        let candidates = shrink_candidates(&json!([5]), &typ);
357→        assert!(candidates.contains(&json!([]))); // empty
358→        // Also contains element-shrunk variants like [0], [1], [-1].
359→        assert!(candidates.contains(&json!([0])));
360→    }
