531→
532→    mod prop_tests {
533→        use super::*;
534→        use proptest::prelude::*;
535→        use serde_json::json;
536→
537→        proptest! {
538→            #[test]
539→            fn shrink_never_contains_original_int(n in any::<i64>()) {
540→                let val = json!(n);
541→                let candidates = shrink_candidates(&val, &TypeInfo::Int);
542→                prop_assert!(
543→                    !candidates.contains(&val),
544→                    "candidates for {val:?} should not contain original"
545→                );
546→            }
547→
548→            #[test]
549→            fn shrink_never_contains_original_float(
550→                n in (-1000i32..1000).prop_map(|n| f64::from(n))
551→            ) {
552→                let val = json!(n);
553→                let candidates = shrink_candidates(&val, &TypeInfo::Float);
554→                prop_assert!(
555→                    !candidates.contains(&val),
556→                    "candidates for {val:?} should not contain original"
557→                );
558→            }
559→
560→            #[test]
561→            fn shrink_never_contains_original_str(s in ".{0,20}") {
562→                let val = json!(s);
563→                let candidates = shrink_candidates(&val, &TypeInfo::Str);
564→                prop_assert!(
565→                    !candidates.contains(&val),
566→                    "candidates for {val:?} should not contain original"
567→                );
568→            }
569→
570→            #[test]
571→            fn shrink_int_candidates_are_ints(n in any::<i64>()) {
572→                let val = json!(n);
573→                for c in shrink_candidates(&val, &TypeInfo::Int) {
574→                    prop_assert!(
575→                        c.is_i64() || c.is_u64(),
576→                        "shrink candidate {c:?} is not an int"
577→                    );
578→                }
579→            }
580→
581→            #[test]
582→            fn shrink_float_candidates_are_floats(
583→                n in (-1000i32..1000).prop_map(|n| f64::from(n))
584→            ) {
585→                let val = json!(n);
586→                for c in shrink_candidates(&val, &TypeInfo::Float) {
587→                    prop_assert!(
588→                        c.is_f64() || c.is_i64() || c.is_u64(),
589→                        "shrink candidate {c:?} is not a float"
590→                    );
591→                }
592→            }
593→
594→            #[test]
595→            fn shrink_str_candidates_are_strings(s in ".{0,20}") {
596→                let val = json!(s);
597→                for c in shrink_candidates(&val, &TypeInfo::Str) {
598→                    prop_assert!(c.is_string(),
599→                        "shrink candidate {c:?} is not a string");
600→                }
601→            }
602→
603→            #[test]
604→            fn shrink_int_abs_leq_or_boundary(n in -1_000_000i64..1_000_000i64) {
605→                let val = json!(n);
606→                let abs_n = n.unsigned_abs();
607→                for c in shrink_candidates(&val, &TypeInfo::Int) {
608→                    let c_n = c.as_i64().unwrap();
609→                    let is_boundary = c_n == 0 || c_n == 1 || c_n == -1;
610→                    prop_assert!(
611→                        c_n.unsigned_abs() <= abs_n || is_boundary,
612→                        "shrink candidate {c_n} has |c| > |{n}| and is not a boundary"
613→                    );
614→                }
615→            }
616→
617→            #[test]
618→            fn shrink_str_len_leq_original(s in ".{0,30}") {
619→                let val = json!(s);
620→                let orig_len = s.chars().count();
621→                for c in shrink_candidates(&val, &TypeInfo::Str) {
622→                    let c_str = c.as_str().unwrap();
623→                    prop_assert!(
624→                        c_str.chars().count() <= orig_len,
625→                        "shrink candidate {:?} longer than original {:?}",
626→                        c_str, s
627→                    );
628→                }
629→            }
630→
631→            #[test]
632→            fn shrink_array_len_leq_original(len in 0..6usize) {
633→                let arr: Vec<Value> = (0..len).map(|i| json!(i as i64)).collect();
634→                let val = Value::Array(arr);
635→                let typ = TypeInfo::Array { element: Box::new(TypeInfo::Int) };
636→
637→                for c in shrink_candidates(&val, &typ) {
638→                    let c_arr = c.as_array().unwrap();
639→                    prop_assert!(
640→                        c_arr.len() <= len,
641→                        "shrink candidate array len {} > original len {}",
642→                        c_arr.len(), len
643→                    );
644→                }
645→            }
646→
647→            #[test]
648→            fn shrink_no_duplicates_int(n in any::<i64>()) {
649→                let candidates = shrink_candidates(&json!(n), &TypeInfo::Int);
650→                for (i, a) in candidates.iter().enumerate() {
651→                    for (j, b) in candidates.iter().enumerate() {
652→                        if i != j {
653→                            prop_assert!(a != b, "duplicate candidates for {}", n);
654→                        }
655→                    }
656→                }
657→            }
