 56→/// Return a realistic heuristic string if `name` matches a known pattern.
 57→///
 58→/// Uses case-insensitive substring matching against `NAME_HEURISTICS`.
 59→/// Returns the first match, so ordering in the table controls priority.
 60→fn heuristic_string_for_name(name: &str) -> Option<&'static str> {
 61→    let lower = name.to_ascii_lowercase();
 62→    NAME_HEURISTICS.iter().find_map(|h| {
 63→        h.substrings
 64→            .iter()
 65→            .any(|s| lower.contains(s))
 66→            .then_some(h.value)
 67→    })
 68→}
