139→/// Generate a random string from a small vocabulary plus random characters.
140→fn generate_string(rng: &mut impl Rng) -> Value {
141→    let choice: u8 = rng.random_range(0..10);
142→    let s = match choice {
143→        0 => String::new(),
144→        1 => "hello".to_string(),
145→        2 => "test".to_string(),
146→        3 => " ".to_string(),
147→        4 => "0".to_string(),
148→        5 => "true".to_string(),
149→        6 => "null".to_string(),
150→        _ => {
151→            let len = rng.random_range(1..=20);
152→            (0..len)
153→                .map(|_| rng.random_range(b'a'..=b'z') as char)
154→                .collect()
155→        }
156→    };
157→    json!(s)
158→}
