 863→
 864→impl PrefetchedValues {
 865→    /// Create an empty prefetch store.
 866→    #[must_use]
 867→    pub fn new() -> Self {
 868→        Self {
 869→            entries: std::collections::HashMap::new(),
 870→        }
 871→    }
 872→
 873→    /// Insert generated values for a specific generator (legacy API, no metadata).
 874→    pub fn insert(&mut self, file: String, name: String, vals: Vec<Value>) {
 875→        let entries: Vec<GeneratedEntry> = vals
 876→            .into_iter()
 877→            .map(|v| {
 878→                let composite = crate::canonical_json::composite_id("unknown", &v);
 879→                GeneratedEntry {
 880→                    value: v,
 881→                    generator_id: "unknown".into(),
 882→                    recipe: None,
 883→                    composite_id: composite,
 884→                }
 885→            })
 886→            .collect();
 887→        self.entries.entry((file, name)).or_default().extend(entries);
 888→    }
 889→
 890→    /// Insert a fully-formed generated entry with metadata.
 891→    pub fn insert_entry(&mut self, file: String, name: String, entry: GeneratedEntry) {
 892→        self.entries.entry((file, name)).or_default().push(entry);
 893→    }
 894→
 895→    /// Take the next value for a generator, if available.
 896→    pub fn take(&mut self, file: &str, name: &str) -> Option<Value> {
 897→        self.take_entry(file, name).map(|e| e.value)
 898→    }
 899→
 900→    /// Take the next entry (value + metadata) for a generator, if available.
 901→    pub fn take_entry(&mut self, file: &str, name: &str) -> Option<GeneratedEntry> {
 902→        let key = (file.to_string(), name.to_string());
 903→        let queue = self.entries.get_mut(&key)?;
 904→        if queue.is_empty() {
 905→            None
 906→        } else {
 907→            Some(queue.remove(0))
 908→        }
 909→    }
 910→
 911→    /// Check whether a generator has remaining values.
 912→    #[must_use]
 913→    pub fn has_values(&self, file: &str, name: &str) -> bool {
 914→        self.entries
 915→            .get(&(file.to_string(), name.to_string()))
 916→            .is_some_and(|q| !q.is_empty())
 917→    }
 918→}
