                        inputs: interp,
                        source: InputSource::BoundarySearch,
                    });
                    boundary_generated += 1;
                }
                boundary_attempted = true;
            }
        }
    }
}

// Phase 2: Fall back to blind fuzzing if boundary search wasn't applicable
// (no opposite-side witness available yet).
if !boundary_attempted {
    for (i, constraint_opt) in sym_constraints.iter().enumerate() {
