            let lo = a.min(b);
            let hi = a.max(b);
            for mid in &results {
                let v = mid.as_i64().unwrap();
                prop_assert!(v >= lo && v <= hi,
                    "midpoint {} not in range [{}, {}]", v, lo, hi);
            }
        }

        #[test]
        fn interpolate_float_midpoint_in_range(
            a in proptest::num::f64::NORMAL,
